1	//! `show` subcommand — for each commit in a revision range, print
2	//! author / committer / ids / parents / children / branches /
3	//! follows / precedes / description body / a changed-files summary.
4	//!
5	//! - `ShowArgs`: clap surface; flattens
6	//!   `options_flags::common_args::CommonArgs` plus a `-f`/`--files`
7	//!   cap (raw `String`; parsed at the boundary into [`FileLimit`]).
8	//! - `ShowParams`: clap-free; embeds `common::CommonParams` and the
9	//!   parsed `FileLimit`. Built via `TryFrom<&ShowArgs>` at the
10	//!   binary edge.
11	//! - `show(&Context, &ShowParams)`: the op — `for_each_repo`, one
12	//!   `show_one_commit` per commit.
13	
14	use std::sync::Arc;
15	
16	use chrono::Offset;
17	use clap::Args;
18	use jj_lib::backend::TreeValue;
19	use jj_lib::commit::Commit;
20	use jj_lib::matchers::EverythingMatcher;
21	use jj_lib::merged_tree::TreeDiffIterator;
22	use jj_lib::object_id::ObjectId;
23	use jj_lib::repo::{ReadonlyRepo, Repo};
24	use jj_lib::workspace::Workspace;
25	use pollster::FutureExt;
26	
27	use log::{debug, info};
28	
29	use crate::common::{self, CommonParams};
30	use crate::context::Context;
31	use crate::options_flags::common_args::CommonArgs;
32	
33	/// Parsed file limit: None (suppress), Some(n) (cap at n), or all.
34	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
35	pub enum FileLimit {
36	    /// Don't show changed files section at all.
37	    None,
38	    /// Show up to N files (with first/last split if truncated).
39	    Cap(usize),
40	    /// Show all files.
41	    All,
42	}
43	
44	impl FileLimit {
45	    /// Parse the `--files` flag string into a `FileLimit` — `"0"` →
46	    /// None, `"all"` → All, otherwise a positive integer → Cap(n).
47	    /// Called at the boundary by `ShowParams::try_from`.
48	    pub fn parse(s: &str) -> Result<Self, String> {
49	        match s {
50	            "0" => Ok(FileLimit::None),
51	            "all" => Ok(FileLimit::All),
52	            _ => s
53	                .parse::<usize>()
54	                .map(FileLimit::Cap)
55	                .map_err(|_| format!("invalid file limit '{s}': expected number, 0, or 'all'")),
56	        }
57	    }
58	}
59	
60	#[derive(Args, Debug)]
61	pub struct ShowArgs {
62	    #[command(flatten)]
63	    pub common: CommonArgs,
64	
65	    /// Max changed files: number, 0 (none), or 'all'
66	    #[arg(short = 'f', long = "files", default_value = "50")]
67	    pub files: String,
68	}
69	
70	/// Clap-free params for `show`; embeds `CommonParams` plus the parsed
71	/// `FileLimit`.
72	#[derive(Debug)]
73	pub struct ShowParams {
74	    pub common: CommonParams,
75	    pub files: FileLimit,
76	}
77	
78	impl TryFrom<&ShowArgs> for ShowParams {
79	    type Error = String;
80	
81	    /// Resolve clap `ShowArgs` into `ShowParams`: delegate to
82	    /// `CommonParams::try_from` for the shared fields and parse
83	    /// `--files` into `FileLimit` at the boundary. Fallible for two
84	    /// reasons (`resolve_repos` or `FileLimit::parse`); both errors
85	    /// surface as `String` for uniform handling in `main`.
86	    fn try_from(a: &ShowArgs) -> Result<Self, String> {
87	        Ok(ShowParams {
88	            common: CommonParams::try_from(&a.common)?,
89	            files: FileLimit::parse(&a.files)?,
90	        })
91	    }
92	}
93	
94	/// Print full details + a changed-files summary for each commit in
95	/// the resolved range.
96	///
97	/// `_ctx` is unused (show has no user-config or `--log` consumer);
98	/// it's present for the uniform subcommand-layer signature.
99	pub fn show(_ctx: &Context, params: &ShowParams) -> Result<(), Box<dyn std::error::Error>> {
100	    debug!("show: enter");
101	    let c = &params.common;
102	
103	    common::for_each_repo(&c.repos, &c.header, |workspace, repo| {
104	        let (ids, anchor_index) = common::collect_ids(
105	            workspace,
106	            repo,
107	            &c.spec.rev,
108	            c.spec.desc_count,
109	            c.spec.anc_count,
110	        )?;
111	
112	        let mut first = true;
113	        for (i, commit_id) in ids.iter().enumerate() {
114	            if !first {
115	                info!("────────────────────────────────────────");
116	            }
117	            first = false;
118	
119	            let commit = repo.store().get_commit(commit_id)?;
120	            show_one_commit(&commit, workspace, repo, params.files, i == anchor_index)?;
121	        }
122	        Ok(())
123	    })?;
124	    debug!("show: exit");
125	    Ok(())
126	}
127	
128	fn show_one_commit(
129	    commit: &Commit,
130	    workspace: &Workspace,
131	    repo: &Arc<ReadonlyRepo>,
132	    file_limit: FileLimit,
133	    is_primary: bool,
134	) -> Result<(), Box<dyn std::error::Error>> {
135	    // Author
136	    let author = commit.author();
137	    info!(
138	        "Author:    {} <{}> ({})",
139	        author.name,
140	        author.email,
141	        format_timestamp(&author.timestamp)
142	    );
143	
144	    // Committer
145	    let committer = commit.committer();
146	    info!(
147	        "Committer: {} <{}> ({})",
148	        committer.name,
149	        committer.email,
150	        format_timestamp(&committer.timestamp)
151	    );
152	
153	    // Ids
154	    let bookmarks = common::format_bookmarks_at(repo, commit.id());
155	    let ids_line = common::format_commit_short(commit, &bookmarks);
156	    if is_primary {
157	        info!("Ids:       {}", common::bold(&ids_line));
158	    } else {
159	        info!("Ids:       {ids_line}");
160	    }
161	
162	    // Parents
163	    let root_commit_id = repo.store().root_commit_id().clone();
164	    for parent_id in commit.parent_ids() {
165	        if *parent_id == root_commit_id {
166	            continue;
167	        }
168	        let parent = repo.store().get_commit(parent_id)?;
169	        let bm = common::format_bookmarks_at(repo, parent.id());
170	        info!("Parent:    {}", common::format_commit_short(&parent, &bm));
171	    }
172	
173	    // Children
174	    let children_ids =
175	        common::resolve_revset(workspace, repo, &format!("children({})", commit.id().hex()))?;
176	    for child_id in &children_ids {
177	        if *child_id == root_commit_id {
178	            continue;
179	        }
180	        let child = repo.store().get_commit(child_id)?;
181	        let bm = common::format_bookmarks_at(repo, child.id());
182	        info!("Child:     {}", common::format_commit_short(&child, &bm));
183	    }
184	
185	    // Branches
186	    let branches_str = format_branches(commit, workspace, repo)?;
187	    info!("Branches:  {branches_str}");
188	
189	    // Follows
190	    let follows = find_nearest_tag(commit, workspace, repo, true)?;
191	    info!("Follows:   {}", follows.as_deref().unwrap_or("")); // OK: obvious
192	
193	    // Precedes
194	    let precedes = find_nearest_tag(commit, workspace, repo, false)?;
195	    info!("Precedes:  {}", precedes.as_deref().unwrap_or("")); // OK: obvious
196	
197	    // Description (body only — title is on the Ids line)
198	    print_description(commit);
199	
200	    // Changed files
201	    if file_limit != FileLimit::None {
202	        print_diff(commit, repo, file_limit)?;
203	    }
204	
205	    Ok(())
206	}
207	
208	fn find_nearest_tag(
209	    commit: &Commit,
210	    workspace: &Workspace,
211	    repo: &Arc<ReadonlyRepo>,
212	    ancestor: bool,
213	) -> Result<Option<String>, Box<dyn std::error::Error>> {
214	    let commit_hex = commit.id().hex();
215	
216	    let revset_str = if ancestor {
217	        format!("heads(tags() & ::{})", commit_hex)
218	    } else {
219	        format!("roots(tags() & {}::)", commit_hex)
220	    };
221	
222	    let tag_ids = common::resolve_revset(workspace, repo, &revset_str)?;
223	    if tag_ids.is_empty() {
224	        return Ok(None);
225	    }
226	
227	    let tag_id = &tag_ids[0];
228	    let view = repo.view();
229	    for (name, local_remote) in view.tags() {
230	        if local_remote.local_target.added_ids().any(|id| id == tag_id) {
231	            return Ok(Some(name.as_str().to_string()));
232	        }
233	    }
234	
235	    Ok(None)
236	}
237	
238	fn format_branches(
239	    commit: &Commit,
240	    workspace: &Workspace,
241	    repo: &Arc<ReadonlyRepo>,
242	) -> Result<String, Box<dyn std::error::Error>> {
243	    let commit_hex = commit.id().hex();
244	    let view = repo.view();
245	    let mut names: Vec<String> = Vec::new();
246	
247	    for (name, local_remote) in view.bookmarks() {
248	        for bookmark_id in local_remote.local_target.added_ids() {
249	            let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
250	            let results = common::resolve_revset(workspace, repo, &revset_str)?;
251	            if !results.is_empty() {
252	                names.push(name.as_str().to_string());
253	                break;
254	            }
255	        }
256	
257	        for (remote_name, remote_ref) in &local_remote.remote_refs {
258	            if remote_name.as_str() == "git" {
259	                continue;
260	            }
261	            for bookmark_id in remote_ref.target.added_ids() {
262	                let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
263	                let results = common::resolve_revset(workspace, repo, &revset_str)?;
264	                if !results.is_empty() {
265	                    names.push(format!("{}@{}", name.as_str(), remote_name.as_str()));
266	                    break;
267	                }
268	            }
269	        }
270	    }
271	
272	    Ok(names.join(", "))
273	}
274	
275	fn format_timestamp(ts: &jj_lib::backend::Timestamp) -> String {
276	    let millis = ts.timestamp.0;
277	    let secs = millis / 1000;
278	    let tz_minutes = ts.tz_offset;
279	
280	    let dt = chrono::DateTime::from_timestamp(secs, 0)
281	        .unwrap_or_default() // OK: invalid timestamp → epoch for display
282	        .with_timezone(
283	            &chrono::FixedOffset::east_opt(tz_minutes * 60).unwrap_or(chrono::Utc.fix()), // OK: invalid tz → UTC for display
284	        );
285	
286	    dt.format("%Y-%m-%d %H:%M:%S").to_string()
287	}
288	
289	fn print_description(commit: &Commit) {
290	    let desc = commit.description();
291	    let body: String = desc
292	        .lines()
293	        .skip(1)
294	        .skip_while(|l| l.is_empty())
295	        .collect::<Vec<_>>()
296	        .join("\n");
297	
298	    info!("Description:");
299	    for line in body.lines() {
300	        info!("    {line}");
301	    }
302	}
303	
304	fn print_diff(
305	    commit: &Commit,
306	    repo: &Arc<ReadonlyRepo>,
307	    file_limit: FileLimit,
308	) -> Result<(), Box<dyn std::error::Error>> {
309	    let parent_tree = commit.parent_tree(repo.as_ref()).block_on()?;
310	    let commit_tree = commit.tree();
311	
312	    let diff_iter = TreeDiffIterator::new(&parent_tree, &commit_tree, &EverythingMatcher);
313	
314	    let mut lines: Vec<String> = Vec::new();
315	    for entry in diff_iter {
316	        let diff = entry.values?;
317	        let before = diff.before.as_resolved().cloned().flatten();
318	        let after = diff.after.as_resolved().cloned().flatten();
319	
320	        if matches!(&before, Some(TreeValue::Tree(_))) || matches!(&after, Some(TreeValue::Tree(_)))
321	        {
322	            continue;
323	        }
324	
325	        let path_str = entry.path.as_internal_file_string().to_string();
326	
327	        let line = match (before, after) {
328	            (None, Some(value)) => {
329	                format!("    Added {} {path_str}", file_type_str(&value))
330	            }
331	            (Some(_), None) => {
332	                format!(
333	                    "    Removed {} {path_str}",
334	                    file_type_str_from_merged(&diff.before),
335	                )
336	            }
337	            (Some(_), Some(value)) => {
338	                format!("    Modified {} {path_str}", file_type_str(&value))
339	            }
340	            (None, None) => continue,
341	        };
342	        lines.push(line);
343	    }
344	
345	    let total = lines.len();
346	    let cap = match file_limit {
347	        FileLimit::All | FileLimit::None => 0,
348	        FileLimit::Cap(n) => n,
349	    };
350	    let show_all = cap == 0 || total <= cap;
351	
352	    if show_all {
353	        info!("Changed files: {total}");
354	        for line in &lines {
355	            info!("{line}");
356	        }
357	    } else {
358	        info!("Changed files: {total}, showing first {cap}");
359	        for line in &lines[..cap] {
360	            info!("{line}");
361	        }
362	    }
363	
364	    Ok(())
365	}
366	
367	fn file_type_str(value: &TreeValue) -> &'static str {
368	    match value {
369	        TreeValue::File {
370	            executable: false, ..
371	        } => "regular file",
372	        TreeValue::File {
373	            executable: true, ..
374	        } => "executable file",
375	        TreeValue::Symlink(_) => "symlink",
376	        TreeValue::Tree(_) => "tree",
377	        TreeValue::GitSubmodule(_) => "git submodule",
378	    }
379	}
380	
381	fn file_type_str_from_merged(merged: &jj_lib::merge::Merge<Option<TreeValue>>) -> &'static str {
382	    if let Some(Some(value)) = merged.as_resolved() {
383	        file_type_str(value)
384	    } else {
385	        "file"
386	    }
387	}
388	
