106	/// Top-level clone driver.
107	///
108	/// - Resolves TARGET to a concrete clone source (URL or path).
109	/// - Determines destination dir name (`[NAME]` override or
110	///   `derive_name(TARGET)`).
111	/// - Pre-checks target dir doesn't exist.
112	/// - Dispatches to `clone_one` (POR) or `clone_dual` (code,bot).
113	///
114	/// `ctx` is unused today (clone reads neither user config nor the
115	/// `--log` path); it's present for the uniform subcommand-layer
116	/// signature.
117	pub fn clone_repo(_ctx: &Context, params: &CloneParams) -> Result<(), Box<dyn std::error::Error>> {
118	    log::debug!("clone: enter");
119	
120	    let parsed = parse_target(&params.target)?;
121	    let source = match parsed {
122	        Target::Url(u) => u,
123	        Target::OwnerName(o, n) => resolve_url(&format!("{o}/{n}")),
124	        Target::Path(p) => p.to_str().ok_or("path is not valid UTF-8")?.to_string(),
125	        Target::BareName(n) => {
126	            return Err(format!(
127	                "'{n}' is a bare name — clone has no config-driven defaults; \
128	                 use 'owner/{n}', a full URL, or './{n}' for a local path"
129	            )
130	            .into());
131	        }
132	    };
133	
134	    let name = match &params.name {
135	        Some(n) => n.clone(),
136	        None => derive_name(&params.target)?,
137	    };
138	    let parent_dir = std::env::current_dir()?;
139	    let project_dir = parent_dir.join(&name);
140	
141	    if project_dir.exists() {
142	        return Err(format!("'{}' already exists", project_dir.display()).into());
143	    }
144	
145	    if params.dry_run {
146	        info!("Dry run — would execute:");
147	        match params.scope {
148	            ScopeKind::Por => {
149	                info!("  1. jj git clone --colocate {source} {name}");
150	            }
151	            ScopeKind::CodeBot => {
152	                let session_source = derive_session_url(&source);
153	                info!("  1. jj git clone --colocate {source} {name}");
154	                info!("  2. jj git clone --colocate {session_source} {name}/.claude");
155	                info!("  3. Create Claude Code symlink");
156	            }
157	        }
158	        return Ok(());
159	    }
160	
161	    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;
162	
163	    match params.scope {
164	        ScopeKind::Por => {
165	            clone_one(&source, &project_dir, &parent_dir)?;
166	            info!("");
167	            info!("Done! Project cloned to {}", project_dir.display());
168	            info!("  Code repo: {}", project_dir.display());
169	        }
170	        ScopeKind::CodeBot => clone_dual(&source, &project_dir, &parent_dir)?,
171	    }
172	
173	    log::debug!("clone: exit");
174	    Ok(())
175	}
